// Filter CleaningJobs to only rows eligible for payroll.
// Eligible: status=COMPLETED, payrollStatus empty or NOT_STARTED, both clock times present.
const allJobs = $('Read CleaningJobs').all();

const eligible = allJobs.filter(item => {
  const j = item.json || {};
  const status        = (j.status        || '').toString().trim();
  const payrollStatus = (j.payrollStatus || '').toString().trim();
  const clockIn       = (j.clockInTimeUTC  || '').toString().trim();
  const clockOut      = (j.clockOutTimeUTC || '').toString().trim();
  return (
    status === 'COMPLETED' &&
    (payrollStatus === '' || payrollStatus === 'NOT_STARTED') &&
    clockIn  !== '' &&
    clockOut !== ''
  );
});

return eligible;

// Reset summary data from any previous execution.
// $workflow.staticData persists within this execution across SiB iterations.
$workflow.staticData.payrollSummary = {
  processed: [],
  errors:    [],
  startedAt: new Date().toISOString()
};
return $input.all();

const job = $input.first().json;

const clockIn  = new Date(job.clockInTimeUTC);
const clockOut = new Date(job.clockOutTimeUTC);

if (isNaN(clockIn.getTime()) || isNaN(clockOut.getTime())) {
  return [{ json: {
    ...job,
    _payrollError: true,
    _errorMessage: 'Invalid clock time format — could not parse clockInTimeUTC or clockOutTimeUTC'
  }}];
}

const diffMs      = clockOut - clockIn;
const workedHours = Math.round((diffMs / 3600000) * 100) / 100;

let _payrollError = false;
let _errorMessage = '';

if (workedHours < 0) {
  _payrollError = true;
  _errorMessage = 'Negative duration — clock-out is before clock-in';
} else if (workedHours > 12) {
  _payrollError = true;
  _errorMessage = 'Duration exceeds 12 hours — likely data error';
} else if (workedHours === 0) {
  _payrollError = true;
  _errorMessage = 'Zero duration — clock-in equals clock-out';
}

return [{ json: { ...job, workedHours, _payrollError, _errorMessage } }];

const sd = $workflow.staticData;
if (!sd.payrollSummary) sd.payrollSummary = { processed: [], errors: [] };
sd.payrollSummary.errors.push({
  bookingUid:   ($json.bookingUid || '').toString(),
  errorMessage: 'Sanity check failed — see PayrollErrors tab'
});
return $input.all();

const job = $input.first().json;
const cleaners = $('Read CleanersProfile').all();

const row = cleaners.find(r => {
  const c = r.json || r;
  return (c.cleanerId || '').toString().trim() === (job.cleanerId || '').toString().trim();
});

if (!row) {
  return [{ json: {
    ...job,
    _payrollError: true,
    _errorMessage: `Cleaner not found in CleanersProfile — cleanerId: ${job.cleanerId}`
  }}];
}

const c = row.json || row;
const hourlyRate   = parseFloat(c.hourlyRate) || 0;
const cleanerName  = (c.name || c.cleanerName || c.cleanerId || '').toString().trim();
const cleanerEmail = (c.email || '').toString().trim();

if (!hourlyRate || hourlyRate <= 0) {
  return [{ json: {
    ...job,
    _payrollError: true,
    _errorMessage: `Missing or zero hourlyRate for cleanerId: ${job.cleanerId} — add value to CleanersProfile col H`
  }}];
}

return [{ json: {
  ...job,
  _payrollError: false,
  _errorMessage: '',
  cleanerName,
  cleanerEmail,
  hourlyRate
}}];

const sd = $workflow.staticData;
if (!sd.payrollSummary) sd.payrollSummary = { processed: [], errors: [] };
sd.payrollSummary.errors.push({
  bookingUid:   ($json.bookingUid || '').toString(),
  errorMessage: 'Cleaner rate error — see PayrollErrors tab'
});
return $input.all();

const job = $input.first().json;
const properties = $('Read Properties').all();
const row = properties.find(r => {
  const p = r.json || r;
  return (p.propertyUid || '').toString().trim() === (job.propertyUid || '').toString().trim();
});
const propertyName = row
  ? ((row.json || row).propertyName || job.propertyUid || '').toString().trim()
  : (job.propertyUid || '').toString().trim();

return [{ json: { ...job, propertyName } }];

const job = $input.first().json;
const grossPay = Math.round(job.workedHours * job.hourlyRate * 100) / 100;
return [{ json: { ...job, grossPay } }];

// Uses snapshot loaded at startup — avoids hitting Sheets API on every iteration.
// If workflow ran earlier today, new records from that run are NOT in the snapshot,
// so they will be caught by the payrollStatus=READY filter in Filter Eligible Jobs.
const job = $input.first().json;
const existingRecords = $('Read All PayrollRecords').all();
const isDuplicate = existingRecords.some(r => {
  const rec = r.json || r;
  const uid = (rec.bookingUid || '').toString().trim();
  const pid = (rec.payrollId  || '').toString().trim();
  return uid === (job.bookingUid || '').toString().trim() && pid !== '';
});
return [{ json: { ...job, _isDuplicate: isDuplicate } }];

// Reads from Calculate Gross Pay (before GSheets nodes overwrote $json).
const job = $('Calculate Gross Pay').last().json;
const sd  = $workflow.staticData;
if (!sd.payrollSummary) sd.payrollSummary = { processed: [], errors: [] };
sd.payrollSummary.processed.push({
  cleanerName:  (job.cleanerName  || job.cleanerId   || '').toString(),
  propertyName: (job.propertyName || job.propertyUid || '').toString(),
  cleaningDate: (job.cleaningDate || '').toString(),
  workedHours:  job.workedHours || 0,
  grossPay:     job.grossPay    || 0
});
return $input.all();

const sd      = $workflow.staticData;
const summary = sd.payrollSummary || { processed: [], errors: [] };
const today   = new Date().toISOString().slice(0, 10);

const totalHours = summary.processed.reduce((s, j) => s + (j.workedHours || 0), 0);
const totalGross = summary.processed.reduce((s, j) => s + (j.grossPay    || 0), 0);

const jobRows = summary.processed.map(j =>
  `<tr>
    <td style="padding:6px 10px">${j.cleanerName}</td>
    <td style="padding:6px 10px">${j.propertyName}</td>
    <td style="padding:6px 10px">${j.cleaningDate}</td>
    <td style="padding:6px 10px;text-align:right">${Number(j.workedHours).toFixed(2)}h</td>
    <td style="padding:6px 10px;text-align:right">$${Number(j.grossPay).toFixed(2)}</td>
  </tr>`
).join('') || '<tr><td colspan="5" style="padding:6px 10px;color:#888">No jobs processed</td></tr>';

let errorSection = '';
if (summary.errors.length > 0) {
  const errorItems = summary.errors
    .map(e => `<li><strong>${e.bookingUid}</strong>: ${e.errorMessage}</li>`)
    .join('');
  errorSection = `
    <h3 style="color:#c0392b;margin-top:24px">Errors (${summary.errors.length}) — see PayrollErrors tab</h3>
    <ul style="line-height:1.7">${errorItems}</ul>`;
}

const html = `
<h2 style="color:#2c3e50">Payroll Processing Summary — ${today}</h2>
<table style="border-collapse:collapse;margin-bottom:8px">
  <tr><td style="padding:4px 12px 4px 0"><strong>Jobs processed:</strong></td><td>${summary.processed.length}</td></tr>
  <tr><td style="padding:4px 12px 4px 0"><strong>Errors:</strong></td><td>${summary.errors.length}</td></tr>
  <tr><td style="padding:4px 12px 4px 0"><strong>Total hours:</strong></td><td>${totalHours.toFixed(2)}h</td></tr>
  <tr><td style="padding:4px 12px 4px 0"><strong>Total gross pay:</strong></td><td>$$${totalGross.toFixed(2)}</td></tr>
</table>
<h3 style="margin-top:24px">Processed Jobs</h3>
<table border="1" cellspacing="0" style="border-collapse:collapse;border-color:#ddd">
  <thead>
    <tr style="background:#f5f5f5">
      <th style="padding:6px 10px">Cleaner</th>
      <th style="padding:6px 10px">Property</th>
      <th style="padding:6px 10px">Date</th>
      <th style="padding:6px 10px">Hours</th>
      <th style="padding:6px 10px">Gross Pay</th>
    </tr>
  </thead>
  <tbody>${jobRows}</tbody>
  <tfoot>
    <tr style="background:#f5f5f5;font-weight:bold">
      <td colspan="3" style="padding:6px 10px">Total</td>
      <td style="padding:6px 10px;text-align:right">${totalHours.toFixed(2)}h</td>
      <td style="padding:6px 10px;text-align:right">$$${totalGross.toFixed(2)}</td>
    </tr>
  </tfoot>
</table>
${errorSection}
<p style="margin-top:32px;color:#888;font-size:12px">Generated by Workflow 5 – Payroll Processing &bull; ${new Date().toISOString()}</p>`;

// Clean up after use
sd.payrollSummary = null;

return [{ json: {
  subject:     'Payroll Processing Summary — ' + today,
  htmlBody:    html,
  totalJobs:   summary.processed.length + summary.errors.length,
  totalErrors: summary.errors.length,
  totalHours:  Math.round(totalHours * 100) / 100,
  totalGross:  Math.round(totalGross * 100) / 100
}}];
